require"UI.UIBase"require"UI.UIBlock"UI_Pack_Detail=UIBase:Inherit()function UI_Pack_Detail:OnCreate()UI_Pack_Detail.Inst=self;self.ulist=self.scroll.transform:GetComponent(typeof(NormalUList))self.ulist:SetFunc(function(a,b)self:UpdateItem(a,b)end)self.ulist:InitTemp(5)self.ulist:InitValue()end;function UI_Pack_Detail:OnShow(c,d)if self.locking then return end;self.goods_id=d.goodsId;self.when_buy_event=d.buyEvent;local e=ExcelMgr.GetData('shops','goods',self.goods_id)if not e then return end;local f=Tools.ParseItemStr(e.price)self.currency_id=f[1].id;self.item_id=e.item_id;if e.category_goods~=100 then return end;local g=ExcelMgr.GetData('shops','goods_package',e.item_id)if not g or#g==0 then return end;self.packs={}self.origin_total_price=0;local h=ExcelMgr.GetData('item_definition','currency',e.currency).icon;for i=1,3 do self['currency'..i]:SetTextureAsync(Tools.GetPathForUnity(h))end;for i=1,#g do local j=g[i].good_id;local k=g[i].good_count;local l=ExcelMgr.GetData('shops','goods',j)local m=l.price;local n=UI_Shop.goods_discount_value(j)local o=math.floor(m*n)local p=false;if l.category_goods==1 then p=GameMgr.Inst.skin_map[l.item_id]else p=UI_Bag.GetCount(l.item_id)>0 end;table.insert(self.packs,{goods_id=j,count=k,origin_price=m,discount=n,now_price=o,owned=p})if not p then self.origin_total_price=self.origin_total_price+o end end;self.discount_pack=UI_Shop.goods_discount_value(self.goods_id)self.now_total_price=math.floor(self.origin_total_price*self.discount_pack)self.label_discount.text='-'..100-math.ceil(self.discount_pack*100)..'%'self.label_final_price.text=self.now_total_price;self.label_total_price.text=self.origin_total_price;self.ulist:InitPos(#self.packs)self.locking=true;self.transform.gameObject:SetActive(true)self:AnimPopOut(self.root,function()c()self.locking=false end)end;function UI_Pack_Detail:OnClose(c)if self.locking then return end;self.locking=true;self:AnimPopHide(self.root,function()self.locking=false;self.transform.gameObject:SetActive(false)c()end)end;function UI_Pack_Detail:Buy()if self.locking then return end;self:CloseSelf()local q={}local r=self.when_buy_event;local j=self.goods_id;r({event='begin',goods_id=j})local s={}s.goods_id=self.goods_id;s.count=1;s.ver_goods={{id=self.item_id,count=1}}local t=0;for i=1,#self.packs do if not self.packs[i].owned then t=t+self.packs[i].now_price end end;s.ver_price={id=self.currency_id,count=t}local u=ProtoMgr.CreateRequestFromTable('Lobby','buyFromShop',s)LobbyNetMgr.SendRequest('Lobby','buyFromShop',u,function(v,w)if v or w.error.code~=0 then UIMgr.Inst:ShowUI(UI_ErrorInfo.className,nil,{errorType=UI_ErrorInfo.ErrorType.NetWork,method='buyFromShop',error=v,res=w})else AudioMgr.PlayAudio(106)UIMgr.Inst:ShowUI(UI_light_tip.className,nil,{str=Tools.StrOfLocalization(2191)})r({event='success',goods_id=j})end end)end;function UI_Pack_Detail:UpdateItem(a,b)local x=self.packs[b+1]if not x then return end;local e=ExcelMgr.GetData('shops','goods',x.goods_id)local y=a.transform:Find('head')local z=a.transform:Find('head'):Find('icon'):GetComponent(typeof(UnityEngine.UI.Image))if e.category==1 then y:Find('flag_skin').gameObject:SetActive(true)local A=ExcelMgr.GetData('item_definition','skin',e.item_id)z:SetTexture(A.path..'/bighead')else y:Find('flag_skin').gameObject:SetActive(false)z:SetTexture(Tools.GetPathForUnity(e.icon))end;a.transform:Find('name'):GetComponent(typeof(UnityEngine.UI.Text)).text=e['name_'..GameMgr.Inst.prefer_language]a.transform:Find('desc'):GetComponent(typeof(UnityEngine.UI.Text)).text=e['desc_'..GameMgr.Inst.prefer_language]local h=ExcelMgr.GetData('item_definition','currency',e.currency).icon;local B=Tools.GetPathForUnity(h)if x.owned then a.transform:Find('container_buy').gameObject:SetActive(false)a.transform:Find('owned').gameObject:SetActive(true)else a.transform:Find('container_buy').gameObject:SetActive(true)a.transform:Find('container_buy').transform:Find('container_origin_price'):Find('node'):GetComponent(typeof(UnityEngine.UI.Image)):SetTexture(B)a.transform:Find('container_buy').transform:Find('container_discount'):Find('now_currency'):GetComponent(typeof(UnityEngine.UI.Image)):SetTexture(B)a.transform:Find('container_buy').transform:Find('container_discount'):Find('origin_currency'):GetComponent(typeof(UnityEngine.UI.Image)):SetTexture(B)a.transform:Find('owned').gameObject:SetActive(false)self:refresh_price(a.transform:Find('container_buy'),x.origin_price,x.discount)end end;function UI_Pack_Detail:refresh_price(C,D,E)local F=C:Find('container_origin_price')local G=C:Find('container_discount')G.gameObject:SetActive(false)if E>=1 then F.gameObject:SetActive(true)F:Find('now_price'):GetComponent(typeof(UnityEngine.UI.Text)).text=D else G.gameObject:SetActive(true)F.gameObject:SetActive(false)G:Find('discount'):GetComponent(typeof(UnityEngine.UI.Text)).text='-'..100-math.ceil(E*100)..'%'local H=G:Find('now_price'):GetComponent(typeof(UnityEngine.UI.Text))local I=G:Find('origin_price'):GetComponent(typeof(UnityEngine.UI.Text))I.text=D;H.text=math.floor(D*E)end end;return UI_Pack_Detail